const http = require('http');
const url = require('url');

const server = http.createServer((req, res) => {
  const parsedUrl = url.parse(req.url, true);
  if (req.method === 'GET' && parsedUrl.pathname === '/sales') {
    const region = parsedUrl.query.region;
    let data = [];
    if (region === 'US') {
      data = [{ amount: 100 }, { amount: 200 }];
    } else if (region === 'EU') {
      data = [{ amount: 150 }];
    }
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify(data));
  } else {
    res.writeHead(404);
    res.end();
  }
});

const PORT = 8080;
server.listen(PORT, () => {
  console.log(`DB Server listening on port ${PORT}`);
});

import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

interface MyOptions {
  token: string;
}

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
  options: MyOptions,
  policyName: string,
) {
  const authHeader = request.headers.get("authorization");
  if (authHeader !== `Bearer ${options.token}`) {
    return new Response("Unauthorized", { status: 401 });
  }
  return context.next();
}

import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
) {
  const { searchParams } = new URL(request.url);
  const region = searchParams.get("region");
  if (!region) {
    return new Response("Missing region", { status: 400 });
  }
  const response = await fetch(`http://localhost:8080/sales?region=${region}`);
  return response;
}

import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
) {
  const body = await request.json();
  const region = body.region;

  if (!region) {
    return new Response("Missing region", { status: 400 });
  }

  const response = await context.invokeRoute("get-internal-sales", {
    method: "GET",
    searchParams: { region },
    headers: {
      authorization: "Bearer secret-internal-key"
    }
  });

  if (!response.ok) {
    return new Response(`Error fetching sales: ${await response.text()}`, { status: response.status });
  }

  const sales = await response.json();
  const totalSales = sales.reduce((acc: number, item: any) => acc + item.amount, 0);

  return {
    region,
    totalSales
  };
}

